def solve(n: Long, edges: Array[Array[Long]]): Long = {
  import scala.collection.mutable.{PriorityQueue, HashMap}

  val graph = HashMap[Long, Array[(Long, Long)]]()
  for (edge <- edges) {
    val u = edge(0)
    val v = edge(1)
    val w = edge(2)
    graph.putIfAbsent(u, Array.empty[ (Long, Long) ])
    graph(u) = graph(u) :+ (v, w)
  }

  val dist = Array.ofDim[Long](n.toInt, 2)
  for (i <- 0 until n.toInt) {
    dist(i)(0) = Long.MaxValue
    dist(i)(1) = Long.MaxValue
  }
  dist(0)(0) = 0L

  val pq = PriorityQueue[(Long, Long, Boolean)]()
  pq.enqueue((0L, 0L, false))

  while (pq.nonEmpty) {
    val (cost, u, switchUsed) = pq.dequeue()
    if (u == n - 1) return cost

    if (cost > dist(u.toInt)(if (switchUsed) 1 else 0)) {
      continue
    }

    graph.get(u).foreach { case (v, w) =>
      // Case 1: Use the switch at u (if not already used)
      if (!switchUsed) {
        val newCost = cost + 2 * w
        val newSwitchUsed = true
        if (newCost < dist(v.toInt)(newSwitchUsed.toInt)) {
          dist(v.toInt)(newSwitchUsed.toInt) = newCost
          pq.enqueue((newCost, v, newSwitchUsed))
        }
      }

      // Case 2: Don't use the switch at u
      val newSwitchUsed = switchUsed
      val newCost = cost + w
      if (newCost < dist(v.toInt)(newSwitchUsed.toInt)) {
        dist(v.toInt)(newSwitchUsed.toInt) = newCost
        pq.enqueue((newCost, v, newSwitchUsed))
      }
    }
  }

  if (dist(n.toInt - 1)(0) == Long.MaxValue) -1 else dist(n.toInt - 1)(0)
}
